#include <iostream>
#include <fstream>
#include <cmath>
#include <vector>
#include <omp.h>

#define GAMMA 1.4f
#define iterations 2000

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#define BLOCK_SIZE_0 192
#define BLOCK_SIZE_1 192
#define BLOCK_SIZE_2 192
#define BLOCK_SIZE_3 192
#define BLOCK_SIZE_4 192

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

struct float3 {
    float x, y, z;
};

template <typename T>
T* alloc(int N)
{
    return new T[N];
}

template <typename T>
void dealloc(T* array)
{
    delete[] array;
}

template <typename T>
void copy(T* dst, T* src, int N)
{
    for(int i = 0; i < N; i++) dst[i] = src[i];
}

template <typename T>
void upload(T* dst, T* src, int N)
{
    for(int i = 0; i < N; i++) dst[i] = src[i];
}

template <typename T>
void download(T* dst, T* src, int N)
{
    for(int i = 0; i < N; i++) dst[i] = src[i];
}

void dump(float* variables, int nel, int nelr)
{
    float* h_variables = new float[nelr*NVAR];
    download(h_variables, variables, nelr*NVAR);

    {
        std::ofstream file("density");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY*nelr] << std::endl;
    }

    {
        std::ofstream file("momentum");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++)
        {
            for(int j = 0; j != NDIM; j++)
                file << h_variables[i + (VAR_MOMENTUM+j)*nelr] << " ";
            file << std::endl;
        }
    }

    {
        std::ofstream file("density_energy");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
    }
    delete[] h_variables;
}

float ff_variable[NVAR];
float3 ff_flux_contribution_momentum_x[1];
float3 ff_flux_contribution_momentum_y[1];
float3 ff_flux_contribution_momentum_z[1];
float3 ff_flux_contribution_density_energy[1];

void initialize_variables(int nelr, float* variables)
{
    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
        for(int j = 0; j < NVAR; j++)
            variables[i + j*nelr] = ff_variable[j];
}

inline void compute_flux_contribution(float& density, float3& momentum, float& density_energy, float& pressure, float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y, float3& fc_momentum_z, float3& fc_density_energy)
{
    fc_momentum_x.x = velocity.x*momentum.x + pressure;
    fc_momentum_x.y = velocity.x*momentum.y;
    fc_momentum_x.z = velocity.x*momentum.z;

    fc_momentum_y.x = fc_momentum_x.y;
    fc_momentum_y.y = velocity.y*momentum.y + pressure;
    fc_momentum_y.z = velocity.y*momentum.z;

    fc_momentum_z.x = fc_momentum_x.z;
    fc_momentum_z.y = fc_momentum_y.z;
    fc_momentum_z.z = velocity.z*momentum.z + pressure;

    float de_p = density_energy+pressure;
    fc_density_energy.x = velocity.x*de_p;
    fc_density_energy.y = velocity.y*de_p;
    fc_density_energy.z = velocity.z*de_p;
}

inline void compute_velocity(float& density, float3& momentum, float3& velocity)
{
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
}

inline float compute_speed_sqd(float3& velocity)
{
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

inline float compute_pressure(float& density, float& density_energy, float& speed_sqd)
{
    return (float(GAMMA)-float(1.0f))*(density_energy - float(0.5f)*density*speed_sqd);
}

inline float compute_speed_of_sound(float& density, float& pressure)
{
    return sqrtf(float(GAMMA)*pressure/density);
}

void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors)
{
    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
    {
        float density = variables[i + VAR_DENSITY*nelr];
        float3 momentum;
        momentum.x = variables[i + (VAR_MOMENTUM+0)*nelr];
        momentum.y = variables[i + (VAR_MOMENTUM+1)*nelr];
        momentum.z = variables[i + (VAR_MOMENTUM+2)*nelr];

        float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];

        float3 velocity;       compute_velocity(density, momentum, velocity);
        float speed_sqd      = compute_speed_sqd(velocity);
        float pressure       = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = float(0.5f) / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* fluxes)
{
    const float smoothing_coefficient = float(0.2f);

    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
    {
        int j, nb;
        float3 normal; float normal_len;
        float factor;

        float density_i = variables[i + VAR_DENSITY*nelr];
        float3 momentum_i;
        momentum_i.x = variables[i + (VAR_MOMENTUM+0)*nelr];
        momentum_i.y = variables[i + (VAR_MOMENTUM+1)*nelr];
        momentum_i.z = variables[i + (VAR_MOMENTUM+2)*nelr];

        float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

        float3 velocity_i;             				compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i                          = compute_speed_sqd(velocity_i);
        float speed_i                              = sqrtf(speed_sqd_i);
        float pressure_i                           = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i                     = compute_speed_of_sound(density_i, pressure_i);
        float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
        float3 flux_contribution_i_density_energy;
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z, flux_contribution_i_density_energy);

        float flux_i_density = float(0.0f);
        float3 flux_i_momentum;
        flux_i_momentum.x = float(0.0f);
        flux_i_momentum.y = float(0.0f);
        flux_i_momentum.z = float(0.0f);
        float flux_i_density_energy = float(0.0f);

        float3 velocity_nb;
        float density_nb, density_energy_nb;
        float3 momentum_nb;
        float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
        float3 flux_contribution_nb_density_energy;
        float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

        for(j = 0; j < NNB; j++)
        {
            nb = elements_surrounding_elements[i + j*nelr];
            normal.x = normals[i + (j + 0*NNB)*nelr];
            normal.y = normals[i + (j + 1*NNB)*nelr];
            normal.z = normals[i + (j + 2*NNB)*nelr];
            normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

            if(nb >= 0)
            {
                density_nb = variables[nb + VAR_DENSITY*nelr];
                momentum_nb.x = variables[nb + (VAR_MOMENTUM+0)*nelr];
                momentum_nb.y = variables[nb + (VAR_MOMENTUM+1)*nelr];
                momentum_nb.z = variables[nb + (VAR_MOMENTUM+2)*nelr];
                density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                speed_sqd_nb                      = compute_speed_sqd(velocity_nb);
                pressure_nb                       = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                speed_of_sound_nb                 = compute_speed_of_sound(density_nb, pressure_nb);
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z, flux_contribution_nb_density_energy);

                factor = -normal_len*smoothing_coefficient*float(0.5f)*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor*(density_i-density_nb);
                flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
                flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
                flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

                factor = float(0.5f)*normal.x;
                flux_i_density += factor*(momentum_nb.x+momentum_i.x);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

                factor = float(0.5f)*normal.y;
                flux_i_density += factor*(momentum_nb.y+momentum_i.y);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

                factor = float(0.5f)*normal.z;
                flux_i_density += factor*(momentum_nb.z+momentum_i.z);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
            }
            else if(nb == -1)
            {
                flux_i_momentum.x += normal.x*pressure_i;
                flux_i_momentum.y += normal.y*pressure_i;
                flux_i_momentum.z += normal.z*pressure_i;
            }
            else if(nb == -2)
            {
                factor = float(0.5f)*normal.x;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].x+flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].x + flux_contribution_i_momentum_z.x);

                factor = float(0.5f)*normal.y;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].y+flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].y + flux_contribution_i_momentum_z.y);

                factor = float(0.5f)*normal.z;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].z+flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].z + flux_contribution_i_momentum_z.z);
            }
        }

        fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
        fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
        fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
        fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
    }
}

void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes)
{
    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
    {
        float factor = step_factors[i]/float(RK+1-j);

        variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
        variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
        variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
        variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];
        variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];
    }
}

int main(int argc, char** argv)
{
  printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

    if (argc < 2)
    {
        std::cout << "specify data file name" << std::endl;
        return 0;
    }
    const char* data_file_name = argv[1];

    printf("Name:                     OpenMP CPU\n");

    {
        float h_ff_variable[NVAR];
        const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

        h_ff_variable[VAR_DENSITY] = float(1.4);

        float ff_pressure = float(1.0f);
        float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / h_ff_variable[VAR_DENSITY]);
        float ff_speed = float(ff_mach)*ff_speed_of_sound;

        float3 ff_velocity;
        ff_velocity.x = ff_speed*float(cos((float)angle_of_attack));
        ff_velocity.y = ff_speed*float(sin((float)angle_of_attack));
        ff_velocity.z = 0.0f;

        h_ff_variable[VAR_MOMENTUM+0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
        h_ff_variable[VAR_MOMENTUM+1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
        h_ff_variable[VAR_MOMENTUM+2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

        h_ff_variable[VAR_DENSITY_ENERGY] = h_ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

        float3 h_ff_momentum;
        h_ff_momentum.x = *(h_ff_variable+VAR_MOMENTUM+0);
        h_ff_momentum.y = *(h_ff_variable+VAR_MOMENTUM+1);
        h_ff_momentum.z = *(h_ff_variable+VAR_MOMENTUM+2);
        float3 h_ff_flux_contribution_momentum_x;
        float3 h_ff_flux_contribution_momentum_y;
        float3 h_ff_flux_contribution_momentum_z;
        float3 h_ff_flux_contribution_density_energy;
        compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity, h_ff_flux_contribution_momentum_x, h_ff_flux_contribution_momentum_y, h_ff_flux_contribution_momentum_z, h_ff_flux_contribution_density_energy);

        for(int i=0; i<NVAR; i++) ff_variable[i] = h_ff_variable[i];
        ff_flux_contribution_momentum_x[0] = h_ff_flux_contribution_momentum_x;
        ff_flux_contribution_momentum_y[0] = h_ff_flux_contribution_momentum_y;
        ff_flux_contribution_momentum_z[0] = h_ff_flux_contribution_momentum_z;
        ff_flux_contribution_density_energy[0] = h_ff_flux_contribution_density_energy;
    }
    int nel;
    int nelr;

    float* areas;
    int* elements_surrounding_elements;
    float* normals;
    {
        std::ifstream file(data_file_name);

        file >> nel;
        nelr = BLOCK_SIZE_0*((nel / BLOCK_SIZE_0 )+ std::min(1, nel % BLOCK_SIZE_0));

        float* h_areas = new float[nelr];
        int* h_elements_surrounding_elements = new int[nelr*NNB];
        float* h_normals = new float[nelr*NDIM*NNB];

        for(int i = 0; i < nel; i++)
        {
            file >> h_areas[i];
            for(int j = 0; j < NNB; j++)
            {
                file >> h_elements_surrounding_elements[i + j*nelr];
                if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
                h_elements_surrounding_elements[i + j*nelr]--;

                for(int k = 0; k < NDIM; k++)
                {
                    file >> h_normals[i + (j + k*NNB)*nelr];
                    h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
                }
            }
        }

        int last = nel-1;
        for(int i = nel; i < nelr; i++)
        {
            h_areas[i] = h_areas[last];
            for(int j = 0; j < NNB; j++)
            {
                h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];
                for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
            }
        }

        areas = alloc<float>(nelr);
        upload<float>(areas, h_areas, nelr);

        elements_surrounding_elements = alloc<int>(nelr*NNB);
        upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

        normals = alloc<float>(nelr*NDIM*NNB);
        upload<float>(normals, h_normals, nelr*NDIM*NNB);

        delete[] h_areas;
        delete[] h_elements_surrounding_elements;
        delete[] h_normals;
    }

    float* variables = alloc<float>(nelr*NVAR);
    initialize_variables(nelr, variables);

    float* old_variables = alloc<float>(nelr*NVAR);
    float* fluxes = alloc<float>(nelr*NVAR);
    float* step_factors = alloc<float>(nelr);

    initialize_variables(nelr, old_variables);
    initialize_variables(nelr, fluxes);
    for(int i=0; i<nelr; i++) step_factors[i] = 0.0f;

    std::cout << "Starting..." << std::endl;

    double start_time = omp_get_wtime();

    for(int i = 0; i < iterations; i++)
    {
        copy<float>(old_variables, variables, nelr*NVAR);

        compute_step_factor(nelr, variables, areas, step_factors);

        for(int j = 0; j < RK; j++)
        {
            compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes);
            time_step(j, nelr, old_variables, variables, step_factors, fluxes);
        }
    }

    double end_time = omp_get_wtime();
    double elapsed = end_time - start_time;

    std::cout  << elapsed / iterations << " seconds per iteration" << std::endl;

    std::cout << "Saving solution..." << std::endl;
    dump(variables, nel, nelr);
    std::cout << "Saved solution..." << std::endl;

    std::cout << "Cleaning up..." << std::endl;
    dealloc<float>(areas);
    dealloc<int>(elements_surrounding_elements);
    dealloc<float>(normals);

    dealloc<float>(variables);
    dealloc<float>(old_variables);
    dealloc<float>(fluxes);
    dealloc<float>(step_factors);

    std::cout << "Done..." << std::endl;

    return 0;
}

#include <iostream>
#include <fstream>
#include <cmath>
#include <omp.h>

#define GAMMA 1.4f
#define iterations 2000

#define NDIM 3
#define NNB 4

#define RK 3	
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#define BLOCK_SIZE_0 192
#define BLOCK_SIZE_1 192
#define BLOCK_SIZE_2 192
#define BLOCK_SIZE_3 192
#define BLOCK_SIZE_4 192

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

template <typename T>
T* alloc(int N)
{
	T* t = new T[N];
	return t;
}

template <typename T>
void dealloc(T* array)
{
	delete[] array;
}

template <typename T>
void copy(T* dst, T* src, int N)
{
	for(int i = 0; i < N; i++) dst[i] = src[i];
}

template <typename T>
void upload(T* dst, T* src, int N)
{
	for(int i = 0; i < N; i++) dst[i] = src[i];
}

template <typename T>
void download(T* dst, T* src, int N)
{
	for(int i = 0; i < N; i++) dst[i] = src[i];
}

void dump(float* variables, int nel, int nelr)
{
	float* h_variables = new float[nelr*NVAR];
	download(h_variables, variables, nelr*NVAR);

	{
		std::ofstream file("density");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY*nelr] << std::endl;
	}


	{
		std::ofstream file("momentum");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++)
		{
			for(int j = 0; j != NDIM; j++)
				file << h_variables[i + (VAR_MOMENTUM+j)*nelr] << " ";
			file << std::endl;
		}
	}

	{
		std::ofstream file("density_energy");
		file << nel << " " << nelr << std::endl;
		for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
	}
	delete[] h_variables;
}

float ff_variable[NVAR];
float ff_flux_contribution_momentum_x[3];
float ff_flux_contribution_momentum_y[3];
float ff_flux_contribution_momentum_z[3];
float ff_flux_contribution_density_energy[3];

void initialize_variables(int nelr, float* variables)
{
	#pragma omp parallel for
	for(int i = 0; i < nelr; i++)
		for(int j = 0; j < NVAR; j++)
			variables[i + j*nelr] = ff_variable[j];
}

inline void compute_flux_contribution(float& density, float& momentum_x, float& momentum_y, float& momentum_z, float& density_energy, float& pressure, float& velocity_x, float& velocity_y, float& velocity_z, float& fc_momentum_x_x, float& fc_momentum_x_y, float& fc_momentum_x_z, float& fc_momentum_y_x, float& fc_momentum_y_y, float& fc_momentum_y_z, float& fc_momentum_z_x, float& fc_momentum_z_y, float& fc_momentum_z_z, float& fc_density_energy_x, float& fc_density_energy_y, float& fc_density_energy_z)
{
	fc_momentum_x_x = velocity_x*momentum_x + pressure;
	fc_momentum_x_y = velocity_x*momentum_y;
	fc_momentum_x_z = velocity_x*momentum_z;

	fc_momentum_y_x = fc_momentum_x_y;
	fc_momentum_y_y = velocity_y*momentum_y + pressure;
	fc_momentum_y_z = velocity_y*momentum_z;

	fc_momentum_z_x = fc_momentum_x_z;
	fc_momentum_z_y = fc_momentum_y_z;
	fc_momentum_z_z = velocity_z*momentum_z + pressure;

	float de_p = density_energy+pressure;
	fc_density_energy_x = velocity_x*de_p;
	fc_density_energy_y = velocity_y*de_p;
	fc_density_energy_z = velocity_z*de_p;
}

inline void compute_velocity(float& density, float& momentum_x, float& momentum_y, float& momentum_z, float& velocity_x, float& velocity_y, float& velocity_z)
{
	velocity_x = momentum_x / density;
	velocity_y = momentum_y / density;
	velocity_z = momentum_z / density;
}

inline float compute_speed_sqd(float velocity_x, float velocity_y, float velocity_z)
{
	return velocity_x*velocity_x + velocity_y*velocity_y + velocity_z*velocity_z;
}

inline float compute_pressure(float& density, float& density_energy, float& speed_sqd)
{
	return (float(GAMMA)-float(1.0f))*(density_energy - float(0.5f)*density*speed_sqd);
}

inline float compute_speed_of_sound(float& density, float& pressure)
{
	return sqrtf(float(GAMMA)*pressure/density);
}

void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors)
{
	#pragma omp parallel for
	for(int i = 0; i < nelr; i++)
	{
		float density = variables[i + VAR_DENSITY*nelr];
		float momentum_x = variables[i + (VAR_MOMENTUM+0)*nelr];
		float momentum_y = variables[i + (VAR_MOMENTUM+1)*nelr];
		float momentum_z = variables[i + (VAR_MOMENTUM+2)*nelr];

		float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];

		float velocity_x, velocity_y, velocity_z;
		compute_velocity(density, momentum_x, momentum_y, momentum_z, velocity_x, velocity_y, velocity_z);
		float speed_sqd      = compute_speed_sqd(velocity_x, velocity_y, velocity_z);
		float pressure       = compute_pressure(density, density_energy, speed_sqd);
		float speed_of_sound = compute_speed_of_sound(density, pressure);

		step_factors[i] = float(0.5f) / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
	}
}

void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* fluxes)
{
	const float smoothing_coefficient = float(0.2f);

	#pragma omp parallel for
	for(int i = 0; i < nelr; i++)
	{
		float density_i = variables[i + VAR_DENSITY*nelr];
		float momentum_i_x = variables[i + (VAR_MOMENTUM+0)*nelr];
		float momentum_i_y = variables[i + (VAR_MOMENTUM+1)*nelr];
		float momentum_i_z = variables[i + (VAR_MOMENTUM+2)*nelr];
		float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

		float velocity_i_x, velocity_i_y, velocity_i_z;
		compute_velocity(density_i, momentum_i_x, momentum_i_y, momentum_i_z, velocity_i_x, velocity_i_y, velocity_i_z);
		float speed_sqd_i = compute_speed_sqd(velocity_i_x, velocity_i_y, velocity_i_z);
		float speed_i = sqrtf(speed_sqd_i);
		float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
		float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

		float fc_i_momentum_x_x, fc_i_momentum_x_y, fc_i_momentum_x_z;
		float fc_i_momentum_y_x, fc_i_momentum_y_y, fc_i_momentum_y_z;
		float fc_i_momentum_z_x, fc_i_momentum_z_y, fc_i_momentum_z_z;
		float fc_i_density_energy_x, fc_i_density_energy_y, fc_i_density_energy_z;

		compute_flux_contribution(density_i, momentum_i_x, momentum_i_y, momentum_i_z, density_energy_i, pressure_i, velocity_i_x, velocity_i_y, velocity_i_z, fc_i_momentum_x_x, fc_i_momentum_x_y, fc_i_momentum_x_z, fc_i_momentum_y_x, fc_i_momentum_y_y, fc_i_momentum_y_z, fc_i_momentum_z_x, fc_i_momentum_z_y, fc_i_momentum_z_z, fc_i_density_energy_x, fc_i_density_energy_y, fc_i_density_energy_z);

		float flux_i_density = float(0.0f);
		float flux_i_momentum_x = float(0.0f);
		float flux_i_momentum_y = float(0.0f);
		float flux_i_momentum_z = float(0.0f);
		float flux_i_density_energy = float(0.0f);

		for(int j = 0; j < NNB; j++)
		{
			int nb = elements_surrounding_elements[i + j*nelr];
			float normal_x = normals[i + (j + 0*NNB)*nelr];
			float normal_y = normals[i + (j + 1*NNB)*nelr];
			float normal_z = normals[i + (j + 2*NNB)*nelr];
			float normal_len = sqrtf(normal_x*normal_x + normal_y*normal_y + normal_z*normal_z);

			if(nb >= 0) 	
			{
				float density_nb = variables[nb + VAR_DENSITY*nelr];
				float momentum_nb_x = variables[nb + (VAR_MOMENTUM+0)*nelr];
				float momentum_nb_y = variables[nb + (VAR_MOMENTUM+1)*nelr];
				float momentum_nb_z = variables[nb + (VAR_MOMENTUM+2)*nelr];
				float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];

				float velocity_nb_x, velocity_nb_y, velocity_nb_z;
				compute_velocity(density_nb, momentum_nb_x, momentum_nb_y, momentum_nb_z, velocity_nb_x, velocity_nb_y, velocity_nb_z);
				float speed_sqd_nb = compute_speed_sqd(velocity_nb_x, velocity_nb_y, velocity_nb_z);
				float pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
				float speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

				float fc_nb_momentum_x_x, fc_nb_momentum_x_y, fc_nb_momentum_x_z;
				float fc_nb_momentum_y_x, fc_nb_momentum_y_y, fc_nb_momentum_y_z;
				float fc_nb_momentum_z_x, fc_nb_momentum_z_y, fc_nb_momentum_z_z;
				float fc_nb_density_energy_x, fc_nb_density_energy_y, fc_nb_density_energy_z;

				compute_flux_contribution(density_nb, momentum_nb_x, momentum_nb_y, momentum_nb_z, density_energy_nb, pressure_nb, velocity_nb_x, velocity_nb_y, velocity_nb_z, fc_nb_momentum_x_x, fc_nb_momentum_x_y, fc_nb_momentum_x_z, fc_nb_momentum_y_x, fc_nb_momentum_y_y, fc_nb_momentum_y_z, fc_nb_momentum_z_x, fc_nb_momentum_z_y, fc_nb_momentum_z_z, fc_nb_density_energy_x, fc_nb_density_energy_y, fc_nb_density_energy_z);

				float factor = -normal_len*smoothing_coefficient*float(0.5f)*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
				flux_i_density += factor*(density_i-density_nb);
				flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
				flux_i_momentum_x += factor*(momentum_i_x-momentum_nb_x);
				flux_i_momentum_y += factor*(momentum_i_y-momentum_nb_y);
				flux_i_momentum_z += factor*(momentum_i_z-momentum_nb_z);

				factor = float(0.5f)*normal_x;
				flux_i_density += factor*(momentum_nb_x+momentum_i_x);
				flux_i_density_energy += factor*(fc_nb_density_energy_x+fc_i_density_energy_x);
				flux_i_momentum_x += factor*(fc_nb_momentum_x_x+fc_i_momentum_x_x);
				flux_i_momentum_y += factor*(fc_nb_momentum_y_x+fc_i_momentum_y_x);
				flux_i_momentum_z += factor*(fc_nb_momentum_z_x+fc_i_momentum_z_x);

				factor = float(0.5f)*normal_y;
				flux_i_density += factor*(momentum_nb_y+momentum_i_y);
				flux_i_density_energy += factor*(fc_nb_density_energy_y+fc_i_density_energy_y);
				flux_i_momentum_x += factor*(fc_nb_momentum_x_y+fc_i_momentum_x_y);
				flux_i_momentum_y += factor*(fc_nb_momentum_y_y+fc_i_momentum_y_y);
				flux_i_momentum_z += factor*(fc_nb_momentum_z_y+fc_i_momentum_z_y);

				factor = float(0.5f)*normal_z;
				flux_i_density += factor*(momentum_nb_z+momentum_i_z);
				flux_i_density_energy += factor*(fc_nb_density_energy_z+fc_i_density_energy_z);
				flux_i_momentum_x += factor*(fc_nb_momentum_x_z+fc_i_momentum_x_z);
				flux_i_momentum_y += factor*(fc_nb_momentum_y_z+fc_i_momentum_y_z);
				flux_i_momentum_z += factor*(fc_nb_momentum_z_z+fc_i_momentum_z_z);
			}
			else if(nb == -1)	
			{
				flux_i_momentum_x += normal_x*pressure_i;
				flux_i_momentum_y += normal_y*pressure_i;
				flux_i_momentum_z += normal_z*pressure_i;
			}
			else if(nb == -2) 
			{
				factor = float(0.5f)*normal_x;
				flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i_x);
				flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0]+fc_i_density_energy_x);
				flux_i_momentum_x += factor*(ff_flux_contribution_momentum_x[0] + fc_i_momentum_x_x);
				flux_i_momentum_y += factor*(ff_flux_contribution_momentum_y[0] + fc_i_momentum_y_x);
				flux_i_momentum_z += factor*(ff_flux_contribution_momentum_z[0] + fc_i_momentum_z_x);

				factor = float(0.5f)*normal_y;
				flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i_y);
				flux_i_density_energy += factor*(ff_flux_contribution_density_energy[1]+fc_i_density_energy_y);
				flux_i_momentum_x += factor*(ff_flux_contribution_momentum_x[1] + fc_i_momentum_x_y);
				flux_i_momentum_y += factor*(ff_flux_contribution_momentum_y[1] + fc_i_momentum_y_y);
				flux_i_momentum_z += factor*(ff_flux_contribution_momentum_z[1] + fc_i_momentum_z_y);

				factor = float(0.5f)*normal_z;
				flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i_z);
				flux_i_density_energy += factor*(ff_flux_contribution_density_energy[2]+fc_i_density_energy_z);
				flux_i_momentum_x += factor*(ff_flux_contribution_momentum_x[2] + fc_i_momentum_x_z);
				flux_i_momentum_y += factor*(ff_flux_contribution_momentum_y[2] + fc_i_momentum_y_z);
				flux_i_momentum_z += factor*(ff_flux_contribution_momentum_z[2] + fc_i_momentum_z_z);
			}
		}

		fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
		fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum_x;
		fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum_y;
		fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum_z;
		fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
	}
}

void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes)
{
	#pragma omp parallel for
	for(int i = 0; i < nelr; i++)
	{
		float factor = step_factors[i]/float(RK+1-j);

		variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
		variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
		variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
		variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];	
		variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];	
	}
}

int main(int argc, char** argv)
{
  printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

	if (argc < 2)
	{
		std::cout << "specify data file name" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];

	{
		const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

		ff_variable[VAR_DENSITY] = float(1.4);

		float ff_pressure = float(1.0f);
		float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / ff_variable[VAR_DENSITY]);
		float ff_speed = float(ff_mach)*ff_speed_of_sound;

		float ff_velocity_x = ff_speed*float(cos((float)angle_of_attack));
		float ff_velocity_y = ff_speed*float(sin((float)angle_of_attack));
		float ff_velocity_z = 0.0f;

		ff_variable[VAR_MOMENTUM+0] = ff_variable[VAR_DENSITY] * ff_velocity_x;
		ff_variable[VAR_MOMENTUM+1] = ff_variable[VAR_DENSITY] * ff_velocity_y;
		ff_variable[VAR_MOMENTUM+2] = ff_variable[VAR_DENSITY] * ff_velocity_z;

		ff_variable[VAR_DENSITY_ENERGY] = ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

		float ff_momentum_x = ff_variable[VAR_MOMENTUM+0];
		float ff_momentum_y = ff_variable[VAR_MOMENTUM+1];
		float ff_momentum_z = ff_variable[VAR_MOMENTUM+2];

		compute_flux_contribution(ff_variable[VAR_DENSITY], ff_momentum_x, ff_momentum_y, ff_momentum_z, ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity_x, ff_velocity_y, ff_velocity_z, ff_flux_contribution_momentum_x[0], ff_flux_contribution_momentum_x[1], ff_flux_contribution_momentum_x[2], ff_flux_contribution_momentum_y[0], ff_flux_contribution_momentum_y[1], ff_flux_contribution_momentum_y[2], ff_flux_contribution_momentum_z[0], ff_flux_contribution_momentum_z[1], ff_flux_contribution_momentum_z[2], ff_flux_contribution_density_energy[0], ff_flux_contribution_density_energy[1], ff_flux_contribution_density_energy[2]);
	}
	int nel;
	int nelr;

	float* areas;
	int* elements_surrounding_elements;
	float* normals;
	{
		std::ifstream file(data_file_name);

		file >> nel;
		nelr = BLOCK_SIZE_0*((nel / BLOCK_SIZE_0 )+ std::min(1, nel % BLOCK_SIZE_0));

		float* h_areas = new float[nelr];
		int* h_elements_surrounding_elements = new int[nelr*NNB];
		float* h_normals = new float[nelr*NDIM*NNB];

		for(int i = 0; i < nel; i++)
		{
			file >> h_areas[i];
			for(int j = 0; j < NNB; j++)
			{
				file >> h_elements_surrounding_elements[i + j*nelr];
				if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
				h_elements_surrounding_elements[i + j*nelr]--; 

				for(int k = 0; k < NDIM; k++)
				{
					file >> h_normals[i + (j + k*NNB)*nelr];
					h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
				}
			}
		}

		int last = nel-1;
		for(int i = nel; i < nelr; i++)
		{
			h_areas[i] = h_areas[last];
			for(int j = 0; j < NNB; j++)
			{
				h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];	
				for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
			}
		}

		areas = alloc<float>(nelr);
		upload<float>(areas, h_areas, nelr);

		elements_surrounding_elements = alloc<int>(nelr*NNB);
		upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

		normals = alloc<float>(nelr*NDIM*NNB);
		upload<float>(normals, h_normals, nelr*NDIM*NNB);

		delete[] h_areas;
		delete[] h_elements_surrounding_elements;
		delete[] h_normals;
	}

	float* variables = alloc<float>(nelr*NVAR);
	initialize_variables(nelr, variables);

	float* old_variables = alloc<float>(nelr*NVAR);   	
	float* fluxes = alloc<float>(nelr*NVAR);
	float* step_factors = alloc<float>(nelr); 

	initialize_variables(nelr, old_variables);
	initialize_variables(nelr, fluxes);
	for(int i=0; i<nelr; i++) step_factors[i] = 0.0f;

	std::cout << "Starting..." << std::endl;

	double start_time = omp_get_wtime(); 

	for(int i = 0; i < iterations; i++)
	{
		copy<float>(old_variables, variables, nelr*NVAR);

		compute_step_factor(nelr, variables, areas, step_factors);

		for(int j = 0; j < RK; j++)
		{
			compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes);
			time_step(j, nelr, old_variables, variables, step_factors, fluxes);
		}
	}

	double end_time = omp_get_wtime();
	double elapsed = end_time - start_time;

	std::cout  << (elapsed / iterations) << " seconds per iteration" << std::endl;

	std::cout << "Saving solution..." << std::endl;
	dump(variables, nel, nelr);
	std::cout << "Saved solution..." << std::endl;

	std::cout << "Cleaning up..." << std::endl;
	dealloc<float>(areas);
	dealloc<int>(elements_surrounding_elements);
	dealloc<float>(normals);

	dealloc<float>(variables);
	dealloc<float>(old_variables);
	dealloc<float>(fluxes);
	dealloc<float>(step_factors);

	std::cout << "Done..." << std::endl;

	return 0;
}

#include <iostream>
#include <fstream>
#include <cmath>
#include <omp.h>

#define GAMMA 1.4f
#define iterations 2000

#define NDIM 3
#define NNB 4

#define RK 3	
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#define BLOCK_SIZE_0 192
#define BLOCK_SIZE_1 192
#define BLOCK_SIZE_2 192
#define BLOCK_SIZE_3 192
#define BLOCK_SIZE_4 192

#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

struct float3 {
    float x, y, z;
};

template <typename T>
T* alloc(int N)
{
    T* t = new T[N];
    return t;
}

template <typename T>
void dealloc(T* array)
{
    delete[] array;
}

template <typename T>
void copy(T* dst, T* src, int N)
{
    #pragma omp parallel for
    for(int i = 0; i < N; i++)
        dst[i] = src[i];
}

template <typename T>
void upload(T* dst, T* src, int N)
{
    #pragma omp parallel for
    for(int i = 0; i < N; i++)
        dst[i] = src[i];
}

template <typename T>
void download(T* dst, T* src, int N)
{
    #pragma omp parallel for
    for(int i = 0; i < N; i++)
        dst[i] = src[i];
}

void dump(float* variables, int nel, int nelr)
{
    float* h_variables = new float[nelr*NVAR];
    download(h_variables, variables, nelr*NVAR);

    {
        std::ofstream file("density");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY*nelr] << std::endl;
    }

    {
        std::ofstream file("momentum");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++)
        {
            for(int j = 0; j != NDIM; j++)
                file << h_variables[i + (VAR_MOMENTUM+j)*nelr] << " ";
            file << std::endl;
        }
    }

    {
        std::ofstream file("density_energy");
        file << nel << " " << nelr << std::endl;
        for(int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY_ENERGY*nelr] << std::endl;
    }
    delete[] h_variables;
}

float ff_variable[NVAR];
float3 ff_flux_contribution_momentum_x[1];
float3 ff_flux_contribution_momentum_y[1];
float3 ff_flux_contribution_momentum_z[1];
float3 ff_flux_contribution_density_energy[1];

void initialize_variables(int nelr, float* variables)
{
    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
        for(int j = 0; j < NVAR; j++)
            variables[i + j*nelr] = ff_variable[j];
}

inline void compute_flux_contribution(float& density, float3& momentum, float& density_energy, float& pressure, float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y, float3& fc_momentum_z, float3& fc_density_energy)
{
    fc_momentum_x.x = velocity.x*momentum.x + pressure;
    fc_momentum_x.y = velocity.x*momentum.y;
    fc_momentum_x.z = velocity.x*momentum.z;

    fc_momentum_y.x = fc_momentum_x.y;
    fc_momentum_y.y = velocity.y*momentum.y + pressure;
    fc_momentum_y.z = velocity.y*momentum.z;

    fc_momentum_z.x = fc_momentum_x.z;
    fc_momentum_z.y = fc_momentum_y.z;
    fc_momentum_z.z = velocity.z*momentum.z + pressure;

    float de_p = density_energy+pressure;
    fc_density_energy.x = velocity.x*de_p;
    fc_density_energy.y = velocity.y*de_p;
    fc_density_energy.z = velocity.z*de_p;
}

inline void compute_velocity(float& density, float3& momentum, float3& velocity)
{
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
}

inline float compute_speed_sqd(float3& velocity)
{
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

inline float compute_pressure(float& density, float& density_energy, float& speed_sqd)
{
    return (float(GAMMA)-float(1.0f))*(density_energy - float(0.5f)*density*speed_sqd);
}

inline float compute_speed_of_sound(float& density, float& pressure)
{
    return sqrtf(float(GAMMA)*pressure/density);
}

void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors)
{
    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
    {
        float density = variables[i + VAR_DENSITY*nelr];
        float3 momentum;
        momentum.x = variables[i + (VAR_MOMENTUM+0)*nelr];
        momentum.y = variables[i + (VAR_MOMENTUM+1)*nelr];
        momentum.z = variables[i + (VAR_MOMENTUM+2)*nelr];

        float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];

        float3 velocity;       compute_velocity(density, momentum, velocity);
        float speed_sqd      = compute_speed_sqd(velocity);
        float pressure       = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = float(0.5f) / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* fluxes)
{
    const float smoothing_coefficient = float(0.2f);

    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
    {
        int j, nb;
        float3 normal; float normal_len;
        float factor;

        float density_i = variables[i + VAR_DENSITY*nelr];
        float3 momentum_i;
        momentum_i.x = variables[i + (VAR_MOMENTUM+0)*nelr];
        momentum_i.y = variables[i + (VAR_MOMENTUM+1)*nelr];
        momentum_i.z = variables[i + (VAR_MOMENTUM+2)*nelr];

        float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

        float3 velocity_i;             				compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i                          = compute_speed_sqd(velocity_i);
        float speed_i                              = sqrtf(speed_sqd_i);
        float pressure_i                           = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i                     = compute_speed_of_sound(density_i, pressure_i);
        float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
        float3 flux_contribution_i_density_energy;	
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i, flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z, flux_contribution_i_density_energy);

        float flux_i_density = float(0.0f);
        float3 flux_i_momentum;
        flux_i_momentum.x = float(0.0f);
        flux_i_momentum.y = float(0.0f);
        flux_i_momentum.z = float(0.0f);
        float flux_i_density_energy = float(0.0f);

        float3 velocity_nb;
        float density_nb, density_energy_nb;
        float3 momentum_nb;
        float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
        float3 flux_contribution_nb_density_energy;	
        float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

        for(j = 0; j < NNB; j++)
        {
            nb = elements_surrounding_elements[i + j*nelr];
            normal.x = normals[i + (j + 0*NNB)*nelr];
            normal.y = normals[i + (j + 1*NNB)*nelr];
            normal.z = normals[i + (j + 2*NNB)*nelr];
            normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

            if(nb >= 0) 	
            {
                density_nb = variables[nb + VAR_DENSITY*nelr];
                momentum_nb.x = variables[nb + (VAR_MOMENTUM+0)*nelr];
                momentum_nb.y = variables[nb + (VAR_MOMENTUM+1)*nelr];
                momentum_nb.z = variables[nb + (VAR_MOMENTUM+2)*nelr];
                density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];
                compute_velocity(density_nb, momentum_nb, velocity_nb);
                speed_sqd_nb                      = compute_speed_sqd(velocity_nb);
                pressure_nb                       = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                speed_of_sound_nb                 = compute_speed_of_sound(density_nb, pressure_nb);
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb, flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z, flux_contribution_nb_density_energy);

                factor = -normal_len*smoothing_coefficient*float(0.5f)*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor*(density_i-density_nb);
                flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
                flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
                flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

                factor = float(0.5f)*normal.x;
                flux_i_density += factor*(momentum_nb.x+momentum_i.x);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

                factor = float(0.5f)*normal.y;
                flux_i_density += factor*(momentum_nb.y+momentum_i.y);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

                factor = float(0.5f)*normal.z;
                flux_i_density += factor*(momentum_nb.z+momentum_i.z);
                flux_i_density_energy += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
            }
            else if(nb == -1)	
            {
                flux_i_momentum.x += normal.x*pressure_i;
                flux_i_momentum.y += normal.y*pressure_i;
                flux_i_momentum.z += normal.z*pressure_i;
            }
            else if(nb == -2) 
            {
                factor = float(0.5f)*normal.x;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].x+flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].x + flux_contribution_i_momentum_z.x);

                factor = float(0.5f)*normal.y;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].y+flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].y + flux_contribution_i_momentum_z.y);

                factor = float(0.5f)*normal.z;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].z+flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor*(ff_flux_contribution_momentum_x[0].z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor*(ff_flux_contribution_momentum_y[0].z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor*(ff_flux_contribution_momentum_z[0].z + flux_contribution_i_momentum_z.z);

            }
        }

        fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
        fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
        fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
        fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
    }
}

void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes)
{
    #pragma omp parallel for
    for(int i = 0; i < nelr; i++)
    {
        float factor = step_factors[i]/float(RK+1-j);

        variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
        variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
        variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
        variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];	
        variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];	
    }
}

int main(int argc, char** argv)
{
    printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n", BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

    if (argc < 2)
    {
        std::cout << "specify data file name" << std::endl;
        return 0;
    }
    const char* data_file_name = argv[1];

    {
        float h_ff_variable[NVAR];
        const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

        h_ff_variable[VAR_DENSITY] = float(1.4);

        float ff_pressure = float(1.0f);
        float ff_speed_of_sound = sqrt(GAMMA*ff_pressure / h_ff_variable[VAR_DENSITY]);
        float ff_speed = float(ff_mach)*ff_speed_of_sound;

        float3 ff_velocity;
        ff_velocity.x = ff_speed*float(cos((float)angle_of_attack));
        ff_velocity.y = ff_speed*float(sin((float)angle_of_attack));
        ff_velocity.z = 0.0f;

        h_ff_variable[VAR_MOMENTUM+0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
        h_ff_variable[VAR_MOMENTUM+1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
        h_ff_variable[VAR_MOMENTUM+2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

        h_ff_variable[VAR_DENSITY_ENERGY] = h_ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

        float3 h_ff_momentum;
        h_ff_momentum.x = *(h_ff_variable+VAR_MOMENTUM+0);
        h_ff_momentum.y = *(h_ff_variable+VAR_MOMENTUM+1);
        h_ff_momentum.z = *(h_ff_variable+VAR_MOMENTUM+2);
        float3 h_ff_flux_contribution_momentum_x;
        float3 h_ff_flux_contribution_momentum_y;
        float3 h_ff_flux_contribution_momentum_z;
        float3 h_ff_flux_contribution_density_energy;
        compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity, h_ff_flux_contribution_momentum_x, h_ff_flux_contribution_momentum_y, h_ff_flux_contribution_momentum_z, h_ff_flux_contribution_density_energy);

        for(int k=0; k<NVAR; k++) ff_variable[k] = h_ff_variable[k];
        ff_flux_contribution_momentum_x[0] = h_ff_flux_contribution_momentum_x;
        ff_flux_contribution_momentum_y[0] = h_ff_flux_contribution_momentum_y;
        ff_flux_contribution_momentum_z[0] = h_ff_flux_contribution_momentum_z;
        ff_flux_contribution_density_energy[0] = h_ff_flux_contribution_density_energy;
    }
    int nel;
    int nelr;

    float* areas;
    int* elements_surrounding_elements;
    float* normals;
    {
        std::ifstream file(data_file_name);

        file >> nel;
        nelr = BLOCK_SIZE_0*((nel / BLOCK_SIZE_0 )+ std::min(1, nel % BLOCK_SIZE_0));

        float* h_areas = new float[nelr];
        int* h_elements_surrounding_elements = new int[nelr*NNB];
        float* h_normals = new float[nelr*NDIM*NNB];

        for(int i = 0; i < nel; i++)
        {
            file >> h_areas[i];
            for(int j = 0; j < NNB; j++)
            {
                file >> h_elements_surrounding_elements[i + j*nelr];
                if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
                h_elements_surrounding_elements[i + j*nelr]--; 

                for(int k = 0; k < NDIM; k++)
                {
                    file >> h_normals[i + (j + k*NNB)*nelr];
                    h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
                }
            }
        }

        int last = nel-1;
        for(int i = nel; i < nelr; i++)
        {
            h_areas[i] = h_areas[last];
            for(int j = 0; j < NNB; j++)
            {
                h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];	
                for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
            }
        }

        areas = alloc<float>(nelr);
        upload<float>(areas, h_areas, nelr);

        elements_surrounding_elements = alloc<int>(nelr*NNB);
        upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

        normals = alloc<float>(nelr*NDIM*NNB);
        upload<float>(normals, h_normals, nelr*NDIM*NNB);

        delete[] h_areas;
        delete[] h_elements_surrounding_elements;
        delete[] h_normals;
    }

    float* variables = alloc<float>(nelr*NVAR);
    initialize_variables(nelr, variables);

    float* old_variables = alloc<float>(nelr*NVAR);   	
    float* fluxes = alloc<float>(nelr*NVAR);
    float* step_factors = alloc<float>(nelr); 

    initialize_variables(nelr, old_variables);
    initialize_variables(nelr, fluxes);
    for(int i=0; i<nelr; i++) step_factors[i] = 0.0f;

    std::cout << "Starting..." << std::endl;

    double start_time = omp_get_wtime(); 

    for(int i = 0; i < iterations; i++)
    {
        copy<float>(old_variables, variables, nelr*NVAR);

        compute_step_factor(nelr, variables, areas, step_factors);

        for(int j = 0; j < RK; j++)
        {
            compute_flux(nelr, elements_surrounding_elements, normals, variables, fluxes);
            time_step(j, nelr, old_variables, variables, step_factors, fluxes);
        }
    }

    double end_time = omp_get_wtime(); 

    std::cout  << ((end_time - start_time) / iterations) << " seconds per iteration" << std::endl;

    std::cout << "Saving solution..." << std::endl;
    dump(variables, nel, nelr);
    std::cout << "Saved solution..." << std::endl;

    std::cout << "Cleaning up..." << std::endl;
    dealloc<float>(areas);
    dealloc<int>(elements_surrounding_elements);
    dealloc<float>(normals);

    dealloc<float>(variables);
    dealloc<float>(old_variables);
    dealloc<float>(fluxes);
    dealloc<float>(step_factors);

    std::cout << "Done..." << std::endl;

    return 0;
}

