long long get_time() {
	struct timeval tv;
	gettimeofday(&tv, NULL);
	return (tv.tv_sec * 1000000) + tv.tv_usec;
}

void hotspotOpt1(float *p, float* tIn, float *tOut, float sdc,
        int nx, int ny, int nz,
        float ce, float cw, 
        float cn, float cs,
        float ct, float cb, 
        float cc) 
{
    int i, j, k;
    int xy = nx * ny;

    #pragma omp parallel for collapse(2)
    for (j = 0; j < ny; j++) {
        for (i = 0; i < nx; i++) {
            int c = i + j * nx;

            int W = (i == 0)        ? c : c - 1;
            int E = (i == nx-1)     ? c : c + 1;
            int N = (j == 0)        ? c : c - nx;
            int S = (j == ny-1)     ? c : c + nx;

            float temp1, temp2, temp3;
            temp1 = temp2 = tIn[c];
            temp3 = tIn[c+xy];
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp;

            int c_curr = c + xy;
            int W_curr = W + xy;
            int E_curr = E + xy;
            int N_curr = N + xy;
            int S_curr = S + xy;

            for (k = 1; k < nz-1; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c_curr+xy];
                tOut[c_curr] = cc * temp2 + cw * tIn[W_curr] + ce * tIn[E_curr] + cs * tIn[S_curr]
                    + cn * tIn[N_curr] + cb * temp1 + ct * temp3 + sdc * p[c_curr] + ct * amb_temp;
                c_curr += xy;
                W_curr += xy;
                E_curr += xy;
                N_curr += xy;
                S_curr += xy;
            }
            temp1 = temp2;
            temp2 = temp3;
            tOut[c_curr] = cc * temp2 + cw * tIn[W_curr] + ce * tIn[E_curr] + cs * tIn[S_curr]
                + cn * tIn[N_curr] + cb * temp1 + ct * temp3 + sdc * p[c_curr] + ct * amb_temp;
        }
    }
}

void hotspot_opt1(float *p, float *tIn, float *tOut,
        int nx, int ny, int nz,
        float Cap, 
        float Rx, float Ry, float Rz, 
        float dt, int numiter) 
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw =stepDivCap/ Rx;
    cn = cs =stepDivCap/ Ry;
    ct = cb =stepDivCap/ Rz;

    cc = 1.0 - (2.0*ce + 2.0*cn + 3.0*ct);

    size_t s = sizeof(float) * nx * ny * nz;  
    float  *tIn_d, *tOut_d, *p_d;

    tIn_d = (float*)malloc(s);
    tOut_d = (float*)malloc(s);
    p_d = (float*)malloc(s);

    memcpy(tIn_d, tIn, s);
    memcpy(p_d, p, s);

    long long start = get_time();
    for (int i = 0; i < numiter; ++i) {
        hotspotOpt1(p_d, tIn_d, tOut_d, stepDivCap, nx, ny, nz, ce, cw, cn, cs, ct, cb, cc);
        float *t = tIn_d;
        tIn_d = tOut_d;
        tOut_d = t;
    }
    long long stop = get_time();
    float time = (float)((stop - start)/(1000.0 * 1000.0));
    printf("Time: %.3f (s)\n",time);
    memcpy(tOut, tOut_d, s);
    free(p_d);
    free(tIn_d);
    free(tOut_d);
    return;
