int matchQueries(MatchContext* ctx) {
    assert(sizeof(struct PixelOfNode) == sizeof(uint4));
    assert(sizeof(struct PixelOfChildren) == sizeof(uint4));

#if TREE_ACCESS_HISTOGRAM    
	ctx->statistics.node_hist_size = 0;
