	#endif
		CUDA_SAFE_CALL(cudaFree(ref->d_node_tex_array));

	   ref->d_node_tex_array = NULL;


       if (ref->d_children_tex_array)
       {
	#if CHILDTEX
	   CUDA_SAFE_CALL(cudaUnbindTexture( childrentex ) );
	#endif

	CUDA_SAFE_CALL(cudaFree(ref->d_children_tex_array));
