    char* queryreadtimer = createTimer();
    startTimer(queryreadtimer);

    getQueriesTexture(queries->qfile,
                      &queryTex,
                      &queryLen,
                      &queryAddrs,
                      &names,
                      &queryLengths,
                      &numQueries,
					  &num_match_coords,
                      device_mem_avail,
                      ctx->min_match_length,
