	}
}

int solver(	fp** y,
			fp* x,
			int xmax,
			fp* params,
			fp* com,
			fp* d_initvalu,
			fp* d_finavalu,
			fp* d_params,
			fp* d_com) {

	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
	fp* err= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* scale= (fp *) malloc(EQUATIONS* sizeof(fp));
	fp* yy= (fp *) malloc(EQUATIONS* sizeof(fp));

	int i, j, k;

	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		return -2;
	}

	if (xmax == xmin){
		return 0; 
	}

	if (h > (xmax - xmin) ) { 
		h = (fp)xmax - (fp)xmin; 
	}

	for(k=1; k<=xmax; k++) {											

		x[k] = k-1;
		h = h_init;

		scale_fina = 1.0;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(	x[k],
									h,
									y[k-1],
									y[k],
									err,
									params,
									com,
									d_initvalu,
									d_finavalu,
									d_params,
									d_com);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR; 
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
				}
				scale[i] = 0.8 * pow( tolerance * yy[i] / err[i] , err_exponent );
				if(scale[i]<scale_min){
					scale_min = scale[i];
				}
			}
			scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

			for(i=0; i<EQUATIONS; i++){
				if ( err[i] > ( tolerance * yy[i] ) ){
					outside = 1;
				}
			}
			if (outside == 0){
				break;
			}

			h = h * scale_fina;

			if (h >= 0.9) {
				h = 0.9;
			}

			if ( x[k] + h > (fp)xmax ){
				h = (fp)xmax - x[k];
			}

			else if ( x[k] + h + 0.5 * h > (fp)xmax ){
				h = 0.5 * h;
			}

		}

		x[k] = x[k] + h;

		if ( j >= ATTEMPTS ) {
			return -1; 
		}

	}

	free(err);
	free(scale);
	free(yy);

	return 0;
} 

void solver_2(	int workload,
				int xmax,
				fp* x,
				fp* y,
				fp* params,
				fp* com,
				fp* err,
				fp* scale,
				fp* yy,
				fp* initvalu_temp,
				fp* finavalu_temp){

	int tid;																					

	long y_pointer_initial;
	long y_pointer_current; 
	long x_pointer_current;
	int err_pointer;
	int scale_pointer;
	int yy_pointer;
	int params_pointer;
	int initvalu_temp_pointer;
	int finavalu_temp_pointer;
	int com_pointer;

	fp err_exponent ;
	fp h_init;
	fp h;
	fp tolerance;
	int xmin;

	int error;
	int outside;
	fp scale_min;
	fp scale_fina;

	int i, j, k;

#pragma omp parallel for
	for(tid = 0; tid < workload; tid++) {

		err_pointer = tid*EQUATIONS;
		scale_pointer = tid*EQUATIONS;
		yy_pointer = tid*EQUATIONS;
		params_pointer = tid*PARAMETERS;
		initvalu_temp_pointer = tid*EQUATIONS;
		finavalu_temp_pointer = tid*13*EQUATIONS;
		com_pointer = tid*3;

		err_exponent = 1.0 / 7.0;
		h_init = 1;
		h = h_init;
		xmin = 0;
		tolerance = 10 / (fp)(xmax - xmin);

		if (xmax < xmin || h <= 0.0){
			continue;
		}

		if (xmax == xmin){
			continue; 
		}

		if (h > (xmax - xmin) ) { 
			h = (fp)xmax - (fp)xmin; 
		}

		for(k=1; k<(xmax+1); k++) {											

			y_pointer_initial = tid*((xmax+1)*EQUATIONS)+(k-1)*EQUATIONS;
			y_pointer_current = tid*((xmax+1)*EQUATIONS)+k*EQUATIONS;
			x_pointer_current = tid*(xmax+1)+k;

			x[x_pointer_current] = (fp)k;															
			h = h_init;

			scale_fina = 1.0;

			for (j = 0; j < ATTEMPTS; j++) {

				error = 0;
				outside = 0;
				scale_min = MAX_SCALE_FACTOR;

				embedded_fehlberg_7_8_2(	h,																												

											x[x_pointer_current],																				
											&y[y_pointer_initial],																					
											&y[y_pointer_current],																				
											&params[params_pointer],																		

											&err[err_pointer],																						
											&initvalu_temp[initvalu_temp_pointer],													
											&finavalu_temp[finavalu_temp_pointer],													
											&com[com_pointer]);																				

				for(i=0; i<EQUATIONS; i++){
					if(err[err_pointer+i] > 0){
						error = 1;
					}
				}
				if (error != 1) {
					scale_fina = MAX_SCALE_FACTOR; 
					break;
				}

				for(i=0; i<EQUATIONS; i++){
					if(y[y_pointer_initial+i] == 0.0){
						yy[yy_pointer+i] = tolerance;
					}
					else{
						yy[yy_pointer+i] = fabs(y[y_pointer_initial+i]);
					}
					scale[scale_pointer+i] = 0.8 * pow( tolerance * yy[yy_pointer+i] / err[err_pointer+i] , err_exponent );
					if(scale[scale_pointer+i]<scale_min){
						scale_min = scale[scale_pointer+i];
					}
				}
				scale_fina = min( max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);

				for(i=0; i<EQUATIONS; i++){
					if ( err[err_pointer+i] > ( tolerance * yy[yy_pointer+i] ) ){
						outside = 1;
					}
				}
				if (outside == 0){
					break;
				}

				h = h * scale_fina;

				if (h >= 0.9) {
					h = 0.9;
				}

				if ( x[x_pointer_current] + h > (fp)xmax ){
					h = (fp)xmax - x[x_pointer_current];
				}

				else if ( x[x_pointer_current] + h + 0.5 * h > (fp)xmax ){
					h = 0.5 * h;
				}

			}

			x[x_pointer_current] = x[x_pointer_current] + h;

			if ( j >= ATTEMPTS ) {
				continue; 
			}

		}
	}
} 

