    kbt = 0.055*T + 0.0074*pow(T,2) + 0.015*pow(T,3); rcnCKbt = kbt*Pb - kpp1*PP1tot*Pt/(Kmpp1+CaMKIItot*Pt); rcnCKtt2 = kt42*Pt - kt24*pow(Ca,2)*Pt2; rcnCKta = kta*Pt - kat*Ca4CaM*Pa; rcnCKt2a = kt2a*Pt2 - kat2*Ca2CaM*Pa; rcnCKt2b2 = kpp1*PP1tot*Pt2/(Kmpp1+CaMKIItot*Pt2); rcnCKai = kpp1*PP1tot*Pa/(Kmpp1+CaMKIItot*Pa);
    dCaM = 1e-3*(-rcn02 - rcn0B - rcn0CaN); dCa2CaM = 1e-3*(rcn02 - rcn24 - rcn2B - rcn2CaN + CaMKIItot*(-rcnCKib2 + rcnCKt2a)); dCa4CaM = 1e-3*(rcn24 - rcn4B - rcn4CaN + CaMKIItot*(-rcnCKib+rcnCKta));
    dCaMB = 1e-3*(rcn0B-rcn02B); dCa2CaMB = 1e-3*(rcn02B + rcn2B - rcn24B); dCa4CaMB = 1e-3*(rcn24B + rcn4B);
    dPb2 = 1e-3*(rcnCKib2 - rcnCKb2b + rcnCKt2b2); dPb = 1e-3*(rcnCKib + rcnCKb2b - rcnCKbt); dPt = 1e-3*(rcnCKbt-rcnCKta-rcnCKtt2); dPt2 = 1e-3*(rcnCKtt2-rcnCKt2a-rcnCKt2b2); dPa = 1e-3*(rcnCKta+rcnCKt2a-rcnCKai);
    dCa4CaN = 1e-3*(rcnCa4CaN - rcn0CaN - rcn2CaN - rcn4CaN); dCaMCa4CaN = 1e-3*(rcn0CaN - rcn02CaN); dCa2CaMCa4CaN = 1e-3*(rcn2CaN+rcn02CaN-rcn24CaN); dCa4CaMCa4CaN = 1e-3*(rcn4CaN+rcn24CaN);
    d_finavalu[offset_1] = dCaM; d_finavalu[offset_2] = dCa2CaM; d_finavalu[offset_3] = dCa4CaM; d_finavalu[offset_4] = dCaMB; d_finavalu[offset_5] = dCa2CaMB; d_finavalu[offset_6] = dCa4CaMB;
    d_finavalu[offset_7] = dPb2; d_finavalu[offset_8] = dPb; d_finavalu[offset_9] = dPt; d_finavalu[offset_10] = dPt2; d_finavalu[offset_11] = dPa; d_finavalu[offset_12] = dCa4CaN; d_finavalu[offset_13] = dCaMCa4CaN; d_finavalu[offset_14] = dCa2CaMCa4CaN; d_finavalu[offset_15] = dCa4CaMCa4CaN;
    d_finavalu[com_offset] = 1e-3*(2*CaMKIItot*(rcnCKtt2-rcnCKb2b) - 2*(rcn02+rcn24+rcn02B+rcn24B+rcnCa4CaN+rcn02CaN+rcn24CaN));
}

void kernel_fin(fp *initvalu, int initvalu_offset_ecc, int initvalu_offset_Dyad, int initvalu_offset_SL, int initvalu_offset_Cyt, fp *parameter, fp *finavalu, fp JCaDyad, fp JCaSL, fp JCaCyt) {
