    J_cam_SLmyo = kSLmyo*(initvalu[initvalu_offset_SL+0] - initvalu[initvalu_offset_Cyt+0]); J_ca2cam_SLmyo = kSLmyo*(initvalu[initvalu_offset_SL+1] - initvalu[initvalu_offset_Cyt+1]); J_ca4cam_SLmyo = kSLmyo*(initvalu[initvalu_offset_SL+2] - initvalu[initvalu_offset_Cyt+2]);
    finavalu[initvalu_offset_Dyad+0] = finavalu[initvalu_offset_Dyad+0] - J_cam_dyadSL; finavalu[initvalu_offset_Dyad+1] = finavalu[initvalu_offset_Dyad+1] - J_ca2cam_dyadSL; finavalu[initvalu_offset_Dyad+2] = finavalu[initvalu_offset_Dyad+2] - J_ca4cam_dyadSL;
    finavalu[initvalu_offset_SL+0] = finavalu[initvalu_offset_SL+0] + J_cam_dyadSL*Vdyad/VSL - J_cam_SLmyo/VSL; finavalu[initvalu_offset_SL+1] = finavalu[initvalu_offset_SL+1] + J_ca2cam_dyadSL*Vdyad/VSL - J_ca2cam_SLmyo/VSL; finavalu[initvalu_offset_SL+2] = finavalu[initvalu_offset_SL+2] + J_ca4cam_dyadSL*Vdyad/VSL - J_ca4cam_SLmyo/VSL;
