int solver(fp** y, fp* x, int xmax, fp* params, fp* com, fp* d_initvalu, fp* d_finavalu, fp* d_params, fp* d_com) {
    fp err_exponent, h_init, h, tolerance, scale_min, scale_fina;
    int error, outside, xmin, i, j, k;
    fp* err = (fp *) malloc(EQUATIONS* sizeof(fp));
    fp* scale = (fp *) malloc(EQUATIONS* sizeof(fp));
    fp* yy = (fp *) malloc(EQUATIONS* sizeof(fp));

    err_exponent = 1.0 / 7.0; h_init = 1; h = h_init; xmin = 0; tolerance = 10 / (fp)(xmax-xmin);
    x[0] = 0;
    if (xmax < xmin || h <= 0.0){ free(err); free(scale); free(yy); return -2; }
    if (xmax == xmin){ free(err); free(scale); free(yy); return 0; }
    if (h > (xmax - xmin)) h = (fp)xmax - (fp)xmin;

    for(k=1; k<=xmax; k++) {
        x[k] = k-1; h = h_init; scale_fina = 1.0;
        for (j = 0; j < ATTEMPTS; j++) {
            error = 0; outside = 0; scale_min = MAX_SCALE_FACTOR;
            embedded_fehlberg_7_8(x[k], h, y[k-1], y[k], err, params, com, d_initvalu, d_finavalu, d_params, d_com);
            for(i=0; i<EQUATIONS; i++){ if(err[i] > 0) error = 1; }
            if (error != 1) { scale_fina = MAX_SCALE_FACTOR; break; }
            for(i=0; i<EQUATIONS; i++){
                if(y[k-1][i] == 0.0) yy[i] = tolerance; else yy[i] = fabs(y[k-1][i]);
                scale[i] = 0.8 * pow(tolerance * yy[i] / err[i], err_exponent);
                if(scale[i]<scale_min) scale_min = scale[i];
            }
            scale_fina = min(max(scale_min,MIN_SCALE_FACTOR), MAX_SCALE_FACTOR);
            for(i=0; i<EQUATIONS; i++){ if(err[i] > (tolerance * yy[i])) outside = 1; }
            if (outside == 0) break;
            h = h * scale_fina;
            if (h >= 0.9) h = 0.9;
            if (x[k] + h > (fp)xmax) h = (fp)xmax - x[k];
            else if (x[k] + h + 0.5 * h > (fp)xmax) h = 0.5 * h;
        }
        x[k] = x[k] + h;
        if (j >= ATTEMPTS) { free(err); free(scale); free(yy); return -1; }
    }
    free(err); free(scale); free(yy);
    return 0;
}

int work(int xmax, int workload) {
    long long time0, time1, time2, time3, time4, time5;
    long long memory;
    int i, j, status;
    fp*** y; fp** x; fp** params; fp* com;
    fp* d_initvalu, *d_finavalu, *d_params, *d_com;
    FILE * pFile;

    time0 = get_time();
    memory = workload*(xmax+1)*EQUATIONS*4;
    if(memory>1000000000){ printf("ERROR: trying to allocate more than 1.0GB of memory, decrease workload and span parameters or change memory parameter\n"); return 0; }
    time1 = get_time();
    y = (fp ***) malloc(workload* sizeof(fp **));
    for(i=0; i<workload; i++){ y[i] = (fp**)malloc((1+xmax)*sizeof(fp*)); for(j=0; j<(1+xmax); j++){ y[i][j]= (fp *) malloc(EQUATIONS* sizeof(fp)); } }
    x = (fp **) malloc(workload * sizeof(fp *)); for (i= 0; i<workload; i++){ x[i]= (fp *)malloc((1+xmax) *sizeof(fp)); }
