void runTest(int argc, char** argv) {
    int max_rows, max_cols, penalty;
    int *input_itemsets, *output_itemsets, *referrence;
    int size;

    if (argc == 3) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
    } else {
        usage(argc, argv);
    }

    if (atoi(argv[1]) % 16 != 0) {
        fprintf(stderr, "The dimension values must be a multiple of 16\n");
        exit(1);
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;
    referrence = (int *)malloc(max_rows * max_cols * sizeof(int));
    input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    if (!input_itemsets)
        fprintf(stderr, "error: can not allocate memory");

    srand(7);

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    printf("Start Needleman-Wunsch\n");

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }
    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            referrence[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    size = max_cols * max_rows;

    // No CUDA malloc needed, using standard memory

    int block_width = (max_cols - 1) / BLOCK_SIZE;

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    printf("Processing top-left matrix\n");

    for (int i = 1; i <= block_width; i++) {
        // Parallelize over the blocks (which were blockIdx.x in CUDA)
        // Number of blocks for this step is i
        #pragma omp parallel for
        for (int bx = 0; bx < i; bx++) {
            // We need a version of the function that takes bx as argument
            // Refactoring the logic into a helper that accepts bx
            // To avoid code duplication, we'll call a helper function that uses omp_get_thread_num() 
            // but since we are in a parallel for, we can pass bx explicitly if we rewrite the helper.
            // Let's create a helper that takes bx.

            int b_index_x = bx;
            int b_index_y = i - 1 - bx;

            int index   = cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x + (cols + 1);
            // ... (logic inline or called)
            // For clarity and reuse, let's assume we have a function needle_block_1 that takes bx
            // But to match the structure, I'll implement the loop body here or call a refined helper.
            // Refined helper: needle_openmp_block_1(..., bx, ...)
        }
    }

    // Re-writing the loop with explicit helper calls for clarity and correctness
    // Actually, let's just use the helper functions defined above which use omp_get_thread_num()
    // But the parallel region must be set up correctly.

    // Correct approach:
    for (int i = 1; i <= block_width; i++) {
        #pragma omp parallel
        {
            int bx = omp_get_thread_num();
            if (bx < i) {
                // Execute block logic for bx
                // Inline the logic or call a function that accepts bx
                // I will call a specific function for this block execution
                execute_block_1(referrence, input_itemsets, max_cols, penalty, i, block_width, bx);
            }
        }
    }

    printf("Processing bottom-right matrix\n");

    for (int i = block_width - 1; i >= 1; i--) {
        #pragma omp parallel
        {
            int bx = omp_get_thread_num();
            if (bx < i) {
                execute_block_2(referrence, input_itemsets, max_cols, penalty, i, block_width, bx);
            }
        }
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy is implicit as we are using the same array
    // cudaMemcpy(output_itemsets, matrix_cuda, ...) -> data is already in input_itemsets (matrix_cuda)
    // But we need to copy to output_itemsets if they are different arrays. 
    // In the CUDA code, matrix_cuda is updated, then copied to output_itemsets.
    // Here, we updated input_itemsets (which acts as matrix_cuda).
    // So we copy input_itemsets to output_itemsets.
    for (int k = 0; k < size; k++) {
        output_itemsets[k] = input_itemsets[k];
    }

#ifdef TRACEBACK
    FILE *fpo = fopen("result.txt", "w");
    fprintf(fpo, "print traceback value GPU:\n");

    for (int i = max_rows - 2, j = max_rows - 2; i >= 0 && j >= 0; ) {
        int nw, n, w, traceback;
        if (i == max_rows - 2 && j == max_rows - 2)
            fprintf(fpo, "%d ", output_itemsets[i * max_cols + j]);
        if (i == 0 && j == 0)
            break;
        if (i > 0 && j > 0) {
            nw = output_itemsets[(i - 1) * max_cols + j - 1];
            w  = output_itemsets[i * max_cols + j - 1];
            n  = output_itemsets[(i - 1) * max_cols + j];
        }
        else if (i == 0) {
            nw = n = LIMIT;
            w  = output_itemsets[i * max_cols + j - 1];
        }
        else if (j == 0) {
            nw = w = LIMIT;
            n  = output_itemsets[(i - 1) * max_cols + j];
        }

        int new_nw, new_w, new_n;
