void runTest(int argc, char** argv) {
    int max_rows, max_cols, penalty;
    int *input_itemsets, *output_itemsets, *referrence;
    int size;

    if (argc == 3) {
        max_rows = atoi(argv[1]);
        max_cols = atoi(argv[1]);
        penalty = atoi(argv[2]);
    } else {
        usage(argc, argv);
    }

    if (atoi(argv[1]) % 16 != 0) {
        fprintf(stderr, "The dimension values must be a multiple of 16\n");
        exit(1);
    }

    max_rows = max_rows + 1;
    max_cols = max_cols + 1;
    referrence = (int *)malloc(max_rows * max_cols * sizeof(int));
    input_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));
    output_itemsets = (int *)malloc(max_rows * max_cols * sizeof(int));

    if (!input_itemsets)
        fprintf(stderr, "error: can not allocate memory");

    srand(7);

    for (int i = 0; i < max_cols; i++) {
        for (int j = 0; j < max_rows; j++) {
            input_itemsets[i * max_cols + j] = 0;
        }
    }

    printf("Start Needleman-Wunsch\n");

    for (int i = 1; i < max_rows; i++) {
        input_itemsets[i * max_cols] = rand() % 10 + 1;
    }
    for (int j = 1; j < max_cols; j++) {
        input_itemsets[j] = rand() % 10 + 1;
    }

    for (int i = 1; i < max_cols; i++) {
        for (int j = 1; j < max_rows; j++) {
            referrence[i * max_cols + j] = blosum62[input_itemsets[i * max_cols]][input_itemsets[j]];
        }
    }

    for (int i = 1; i < max_rows; i++)
        input_itemsets[i * max_cols] = -i * penalty;
    for (int j = 1; j < max_cols; j++)
        input_itemsets[j] = -j * penalty;

    size = max_cols * max_rows;

    int block_width = (max_cols - 1) / BLOCK_SIZE;

#ifdef TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    printf("Processing top-left matrix\n");

    // Parallelize the blocks for step 1
    // Original: for i=1 to block_width, launch i blocks.
    // We need to simulate: for each i, run i blocks concurrently.
    // Each block has BLOCK_SIZE threads.
    // We use nested parallelism: Outer parallel for over bx, inner parallel for tx.
    // But to ensure concurrency of blocks, the outer loop must be parallel.
    // And inside, we spawn a team for the block.

    for (int i = 1; i <= block_width; i++) {
        // We need to run 'i' blocks.
        // Each block is a team of BLOCK_SIZE threads.
        // We parallelize the loop over bx (0 to i-1).
        // Inside, we create a parallel region of BLOCK_SIZE threads.
        #pragma omp parallel for num_threads(i)
        for (int bx = 0; bx < i; bx++) {
            // Each thread in this loop represents a block.
            // Now we need to spawn BLOCK_SIZE threads for the block logic.
            // Nested parallelism.
            #pragma omp parallel num_threads(BLOCK_SIZE)
            {
                needle_shared_1(referrence, input_itemsets, max_cols, penalty, i, block_width, bx);
            }
        }
    }

    printf("Processing bottom-right matrix\n");

    for (int i = block_width - 1; i >= 1; i--) {
        #pragma omp parallel for num_threads(i)
        for (int bx = 0; bx < i; bx++) {
            #pragma omp parallel num_threads(BLOCK_SIZE)
            {
                needle_shared_2(referrence, input_itemsets, max_cols, penalty, i, block_width, bx);
            }
        }
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    // Copy output (already in input_itemsets as we used it as matrix_cuda)
    // In CUDA, we copied from matrix_cuda to output_itemsets.
    // Here, we updated input_itemsets directly. So copy to output_itemsets.
    memcpy(output_itemsets, input_itemsets, sizeof(int) * size);

#ifdef TRACEBACK
    FILE *fpo = fopen("result.txt", "w");
    fprintf(fpo, "print traceback value GPU:\n");

    for (int i = max_rows - 2, j = max_rows - 2; i >= 0, j >= 0;) {
        int nw, n, w, traceback;
        if (i == max_rows - 2 && j == max_rows - 2)
            fprintf(fpo, "%d ", output_itemsets[i * max_cols + j]);
        if (i == 0 && j == 0)
            break;
        if (i > 0 && j > 0) {
            nw = output_itemsets[(i - 1) * max_cols + j - 1];
