        new_nw = nw + referrence[i * max_cols + j];
        new_w = w - penalty;
        new_n = n - penalty;

        traceback = maximum(new_nw, new_w, new_n);
        if (traceback == new_nw)
            traceback = nw;
        if (traceback == new_w)
            traceback = w;
        if (traceback == new_n)
            traceback = n;

        fprintf(fpo, "%d ", traceback);

        if (traceback == nw) {
            i--; j--; continue;
        } else if (traceback == w) {
            j--; continue;
        } else if (traceback == n) {
            i--; continue;
        }
    }

    fclose(fpo);
#endif

    free(referrence);
    free(input_itemsets);
    free(output_itemsets);

#ifdef TIMING
    printf("Exec: %f\n", kernel_time);
#endif
}

