    // Copy initial data (first row) to src buffer
    for(int i=0; i<cols; i++) {
        gpuResult[0][i] = data[i];
    }

    // gpuWall corresponds to data+cols (rows-1 rows)
    gpuWall = (int*)malloc(sizeof(int)*(size-cols));
    for(int i=0; i<(size-cols); i++) {
        gpuWall[i] = data[cols + i];
    }

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif

    int final_ret = calc_path(gpuWall, gpuResult, rows, cols, \
	 pyramid_height, blockCols, borderCols);

