#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

void dynproc_kernel(
                int iteration, 
                int *gpuWall,
                int *gpuSrc,
                int *gpuResults,
                int cols, 
                int rows,
                int startStep,
                int border)
{
    int blockCols = (cols + border * 2) / (BLOCK_SIZE - iteration * HALO * 2);
    if ((cols + border * 2) % (BLOCK_SIZE - iteration * HALO * 2) != 0) blockCols++;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blockCols; bx++) {
        int prev[BLOCK_SIZE];
        int result_local[BLOCK_SIZE];

        int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;

        int blkX = small_block_cols * bx - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        // Initialize prev for valid range
        for (int tx = validXmin; tx <= validXmax; tx++) {
            int xidx = blkX + tx;
            if (IN_RANGE(xidx, 0, cols - 1)) {
                prev[tx] = gpuSrc[xidx];
            }
        }

        bool computed = false;
        for (int i = 0; i < iteration; i++) {
            computed = false;
            for (int tx = validXmin; tx <= validXmax; tx++) {
                if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2)) {
                    computed = true;
                    int W = tx - 1;
                    int E = tx + 1;
                    W = (W < validXmin) ? validXmin : W;
                    E = (E > validXmax) ? validXmax : E;

                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);
                    int index = cols * (startStep + i) + (blkX + tx);
                    result_local[tx] = shortest + gpuWall[index];
                }
            }

            if (i == iteration - 1) break;

            if (computed) {
                for (int tx = validXmin; tx <= validXmax; tx++) {
                    if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2)) {
                        prev[tx] = result_local[tx];
                    }
                }
            }
        }

        if (computed) {
            for (int tx = validXmin; tx <= validXmax; tx++) {
                int xidx = blkX + tx;
                if (IN_RANGE(xidx, 0, cols - 1)) {
                    if (IN_RANGE(tx, iteration - 1 + 1, BLOCK_SIZE - (iteration - 1) - 2) || iteration == 1) {
                         // Re-check logic: The 'computed' flag in the original code is set inside the loop
                         // based on the current iteration 'i'.
                         // However, the write back happens if 'computed' was true in the last iteration processed.
                         // In the original CUDA code, 'computed' is a local variable per thread.
                         // Here we need to replicate the thread behavior.
                         // The condition for writing is that the thread computed a value in the last step.
                         // Let's re-evaluate the condition for the specific tx.

                         // Actually, the original code:
                         // if (computed) gpuResults[xidx] = result[tx];
                         // 'computed' is true if the thread executed the calculation block in the last iteration.
                         // The calculation block condition: IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid
                         // So for the final write, we check if tx was in range for i = iteration-1.

                         int i_final = iteration - 1;
                         if (IN_RANGE(tx, i_final + 1, BLOCK_SIZE - i_final - 2) && IN_RANGE(tx, validXmin, validXmax)) {
                             gpuResults[xidx] = result_local[tx];
                         }
                    }
                }
            }
        }
        // Correction: The simple loop above for writing is slightly flawed because 'computed' 
        // was a per-thread flag in CUDA. In the sequential block simulation, we just check the condition directly.
        // Let's rewrite the write-back section to be precise.
        for (int tx = validXmin; tx <= validXmax; tx++) {
            int xidx = blkX + tx;
            if (IN_RANGE(xidx, 0, cols - 1)) {
                int i_final = iteration - 1;
                if (IN_RANGE(tx, i_final + 1, BLOCK_SIZE - i_final - 2)) {
                    gpuResults[xidx] = result_local[tx];
                }
            }
        }
    }
}

